class.description:
[HashCalculator] 是 [HashingContext] 的高层封装，用于一次性计算字符串、[PackedByteArray] 或文件路径的哈希值，也可以在一个任务中并行计算多个文件。支持的算法由 [enum HashingContext.HashType] 定义，包括 MD5、SHA-1 和 SHA-256。
计算文件时会按块读取内容，不会把整个文件一次性载入内存。[method start_files] 会使用 [WorkerThreadPool] 在后台并行处理多个文件；可以通过 [method get_progress]、[method get_processed_bytes]、[method get_total_bytes]、[method get_processed_file_count] 和 [method get_total_file_count] 查询进度。结果顺序与输入路径顺序一致。
文件结果以 [Dictionary] 表示，包含以下键：[code]path[/code] 为文件路径，[code]hash[/code] 为 [PackedByteArray] 哈希值，[code]hash_hex[/code] 为十六进制字符串，[code]error[/code] 为 [enum Error] 错误码，[code]size[/code] 为启动时或打开文件后获取的文件大小，[code]processed_size[/code] 为实际读取并参与计算的字节数。若某个文件打不开或读取失败，该项的 [code]error[/code] 不为 [constant OK]，其它文件仍会继续计算。
[codeblocks]
[gdscript]
var md5_hex := HashCalculator.hash_string_hex(HashingContext.HASH_MD5, "hello")

var calculator := HashCalculator.new()
var err := calculator.start_files(HashingContext.HASH_SHA256, PackedStringArray(["res://data/a.bin", "user://b.bin"]))
if err == OK:
	while not calculator.is_finished():
		print(calculator.get_progress())
		await get_tree().process_frame

	for result in calculator.get_results():
		if result.error == OK:
			print(result.path, result.hash_hex)
[/gdscript]
[csharp]
string md5Hex = HashCalculator.HashStringHex(HashingContext.HashType.Md5, "hello");

var calculator = new HashCalculator();
Error err = calculator.StartFiles(HashingContext.HashType.Sha256, new string[] { "res://data/a.bin", "user://b.bin" });
if (err == Error.Ok)
{
	while (!calculator.IsFinished())
	{
		GD.Print(calculator.GetProgress());
		await ToSignal(GetTree(), SceneTree.SignalName.ProcessFrame);
	}

	foreach (Godot.Collections.Dictionary result in calculator.GetResults())
	{
		if ((Error)(int)result["error"] == Error.Ok)
		{
			GD.Print(result["path"], result["hash_hex"]);
		}
	}
}
[/csharp]
[/codeblocks]
